rules.pseudocode:
for each action a in candidate_actions:
    target_food = best_food_toward(a, position, visible_foods)
    if target_food is not None:
        dist = manhattan_distance(next_pos(a), target_food)
        V_I[a] = target_food.palatability * gamma ** dist
    else:
        V_I[a] = 0.0
    # If cached habit Q-value exists for (state_hash, a), blend:
    # V_I[a] = max(V_I[a], Q_habit.get((state_hash, a), 0.0))

for each action a in candidate_actions:
    target_food = best_gd_food_toward(a, position, visible_foods)
    if target_food is not None:
        dist = manhattan_distance(next_pos(a), target_food)
        taste_val = target_food.palatability
        health_val = 1.0 - target_food.palatability
        V_G[a] = (w_tau_G * taste_val + w_h_G * health_val) * gamma ** dist
    else:
        V_G[a] = 0.0
